2. Crea un objeto de configuración de flow pasando tu resolver como parámetro `observerModeResolver:`:

preamble-pd3328598.translation:
```swift showLineNumbers title="Swift"
   do {
       let flowConfiguration = try await AdaptyUI.getFlowConfiguration(
           forFlow: flow,
